import { MittwaldAPIV2Client } from '@mittwald/api-client';

const token = process.env.TEST_CLI_TOKEN || process.env.MITTWALD_API_TOKEN;
if (!token) {
  console.error('Error: TEST_CLI_TOKEN or MITTWALD_API_TOKEN environment variable is required');
  process.exit(1);
}

const client = MittwaldAPIV2Client.newWithToken(token);

console.log('=== FETCHING ALL PROJECTS ===\n');

try {
  // First, get all projects
  const projectsResponse = await client.project.listProjects({});

  if (projectsResponse.status === 200 && projectsResponse.data) {
    console.log(`Found ${projectsResponse.data.length} projects:\n`);

    for (const project of projectsResponse.data) {
      console.log(`\n${'='.repeat(80)}`);
      console.log(`PROJECT: ${project.description || 'Unnamed Project'}`);
      console.log(`ID: ${project.id}`);
      console.log(`Created: ${project.createdAt || 'N/A'}`);
      console.log(`Server ID: ${project.serverId || 'N/A'}`);
      console.log(`${'='.repeat(80)}\n`);

      // For each project, list apps
      try {
        console.log(`  Fetching apps for project ${project.id}...`);
        const appsResponse = await client.app.listApps({
          projectId: project.id
        });

        if (appsResponse.status === 200 && appsResponse.data) {
          if (appsResponse.data.length === 0) {
            console.log(`  No apps found in this project.\n`);
          } else {
            console.log(`  Found ${appsResponse.data.length} apps:\n`);

            appsResponse.data.forEach((app, index) => {
              console.log(`  ${index + 1}. App ID: ${app.id}`);
              console.log(`     Description: ${app.description || 'N/A'}`);
              console.log(`     System Software: ${app.systemSoftware?.name || 'N/A'} ${app.systemSoftware?.version || ''}`);
              console.log(`     Installation Path: ${app.installationPath || 'N/A'}`);
              console.log(`     Document Root: ${app.documentRoot || 'N/A'}`);

              // Show linked databases if available
              if (app.linkedDatabases && app.linkedDatabases.length > 0) {
                console.log(`     Linked Databases: ${app.linkedDatabases.length}`);
              }

              console.log('');
            });
          }
        } else {
          console.log(`  Could not fetch apps (status: ${appsResponse.status})\n`);
        }
      } catch (appError) {
        console.log(`  Error fetching apps: ${appError.message}\n`);
      }

      // Try to list services (which includes containers)
      try {
        console.log(`  Fetching services for project ${project.id}...`);
        // Use the raw HTTP client to access services endpoint
        const servicesUrl = `https://api.mittwald.de/v2/projects/${project.id}/services`;
        const response = await fetch(servicesUrl, {
          headers: {
            'Authorization': `Bearer ${token}`
          }
        });

        if (response.ok) {
          const services = await response.json();
          if (services && services.length > 0) {
            console.log(`  Found ${services.length} services:\n`);
            services.forEach((service, index) => {
              console.log(`  ${index + 1}. Service: ${service.kind || 'N/A'}`);
              console.log(`     ID: ${service.id}`);
              if (service.image) console.log(`     Image: ${service.image}`);
              if (service.description) console.log(`     Description: ${service.description}`);
              console.log('');
            });
          } else {
            console.log(`  No services found in this project.\n`);
          }
        } else {
          console.log(`  Could not fetch services (status: ${response.status})\n`);
        }
      } catch (serviceError) {
        console.log(`  Error fetching services: ${serviceError.message}\n`);
      }
    }

    console.log(`\n${'='.repeat(80)}`);
    console.log(`SUMMARY: ${projectsResponse.data.length} total projects`);
    console.log(`${'='.repeat(80)}\n`);

  } else {
    console.log('No projects found or error occurred');
    console.log('Status:', projectsResponse.status);
  }
} catch (error) {
  console.error('Error listing projects:', error.message);
  if (error.response) {
    console.error('Response status:', error.response.status);
    console.error('Response data:', error.response.data);
  }
}

